import{_ as e,o as l,c as n,a2 as d}from"./chunks/framework.Crpw6aS5.js";const o=JSON.parse('{"title":"1968年致合伙人信","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1968年/翻译.md","filePath":"01_letters/1968年/翻译.md"}'),r={name:"01_letters/1968年/翻译.md"};function a(i,t,s,g,c,x){return l(),n("div",null,[...t[0]||(t[0]=[d('<h1 id="_1968年致合伙人信" tabindex="-1">1968年致合伙人信 <a class="header-anchor" href="#_1968年致合伙人信" aria-label="Permalink to &quot;1968年致合伙人信&quot;">​</a></h1><h2 id="_1968年业绩" tabindex="-1">1968年业绩 <a class="header-anchor" href="#_1968年业绩" aria-label="Permalink to &quot;1968年业绩&quot;">​</a></h2><p><strong>人非圣贤，孰能无过。</strong></p><p>1968年初，我认为巴菲特合伙公司的前景比历史上任何时期都更为黯淡。然而，由于一个简单但正确的理念终于迎来时机（投资理念就像女人——往往充满诱惑却未必守时），我们实现了整体收益40,032,691美元。</p><p>诸位自然具有足够的理智，不会为美元数字所动，而是要求以道琼斯工业平均指数为基准来衡量业绩。我们创下了新纪录：合伙公司整体收益 <strong>+58.8%</strong>，道指整体收益（含全年股息） <strong>+7.7%</strong>。这一结果应当被视为桥牌中摸到十三张黑桃式的异常好运——你叫了满贯，成功了，看起来很低调，赢钱入袋，然后回归正事继续打局牌分。当然，我们的牌也有被吃的份儿。</p><p>以下为各年度道指收益、合伙公司收益（税前，扣除超额部分四分之一归普通合伙人）以及有限合伙人收益的总结：</p><table tabindex="0"><thead><tr><th style="text-align:center;">年份</th><th style="text-align:center;">道指整体收益（1）</th><th style="text-align:center;">合伙公司收益（2）</th><th style="text-align:center;">有限合伙人收益（3）</th></tr></thead><tbody><tr><td style="text-align:center;">1957</td><td style="text-align:center;">-8.4%</td><td style="text-align:center;">10.4%</td><td style="text-align:center;">9.3%</td></tr><tr><td style="text-align:center;">1958</td><td style="text-align:center;">38.5%</td><td style="text-align:center;">40.9%</td><td style="text-align:center;">32.2%</td></tr><tr><td style="text-align:center;">1959</td><td style="text-align:center;">20.0%</td><td style="text-align:center;">25.9%</td><td style="text-align:center;">20.9%</td></tr><tr><td style="text-align:center;">1960</td><td style="text-align:center;">-6.2%</td><td style="text-align:center;">22.8%</td><td style="text-align:center;">18.6%</td></tr><tr><td style="text-align:center;">1961</td><td style="text-align:center;">22.4%</td><td style="text-align:center;">45.9%</td><td style="text-align:center;">35.9%</td></tr><tr><td style="text-align:center;">1962</td><td style="text-align:center;">-7.6%</td><td style="text-align:center;">13.9%</td><td style="text-align:center;">11.9%</td></tr><tr><td style="text-align:center;">1963</td><td style="text-align:center;">20.6%</td><td style="text-align:center;">38.7%</td><td style="text-align:center;">30.5%</td></tr><tr><td style="text-align:center;">1964</td><td style="text-align:center;">18.7%</td><td style="text-align:center;">27.8%</td><td style="text-align:center;">22.3%</td></tr><tr><td style="text-align:center;">1965</td><td style="text-align:center;">14.2%</td><td style="text-align:center;">47.2%</td><td style="text-align:center;">36.9%</td></tr><tr><td style="text-align:center;">1966</td><td style="text-align:center;">-15.6%</td><td style="text-align:center;">20.4%</td><td style="text-align:center;">16.8%</td></tr><tr><td style="text-align:center;">1967</td><td style="text-align:center;">19.0%</td><td style="text-align:center;">35.9%</td><td style="text-align:center;">28.4%</td></tr><tr><td style="text-align:center;">1968</td><td style="text-align:center;">7.7%</td><td style="text-align:center;">58.8%</td><td style="text-align:center;">45.6%</td></tr></tbody></table><blockquote><p>（1）以道指年度涨跌加上全年持有道指本应获得的股息为基础计算。 （2）1957-1961年为所有存续完整年度的各前身有限合伙企业的综合收益，含所有费用后，但在合伙人分配或普通合伙人提成之前。 （3）1957-1961年以前列合伙公司收益为基础，按现行合伙协议扣除普通合伙人提成后计算，但不含有限合伙人月度提取。</p></blockquote><p>累计复合收益结果如下：</p><table tabindex="0"><thead><tr><th style="text-align:center;">年份</th><th style="text-align:center;">道指整体收益</th><th style="text-align:center;">合伙公司收益</th><th style="text-align:center;">有限合伙人收益</th></tr></thead><tbody><tr><td style="text-align:center;">1957</td><td style="text-align:center;">-8.4%</td><td style="text-align:center;">10.4%</td><td style="text-align:center;">9.3%</td></tr><tr><td style="text-align:center;">1957-58</td><td style="text-align:center;">26.9%</td><td style="text-align:center;">55.6%</td><td style="text-align:center;">44.5%</td></tr><tr><td style="text-align:center;">1957-59</td><td style="text-align:center;">52.3%</td><td style="text-align:center;">95.9%</td><td style="text-align:center;">74.7%</td></tr><tr><td style="text-align:center;">1957-60</td><td style="text-align:center;">42.9%</td><td style="text-align:center;">140.6%</td><td style="text-align:center;">107.2%</td></tr><tr><td style="text-align:center;">1957-61</td><td style="text-align:center;">74.9%</td><td style="text-align:center;">251.0%</td><td style="text-align:center;">181.6%</td></tr><tr><td style="text-align:center;">1957-62</td><td style="text-align:center;">61.6%</td><td style="text-align:center;">299.8%</td><td style="text-align:center;">215.1%</td></tr><tr><td style="text-align:center;">1957-63</td><td style="text-align:center;">95.1%</td><td style="text-align:center;">454.5%</td><td style="text-align:center;">311.2%</td></tr><tr><td style="text-align:center;">1957-64</td><td style="text-align:center;">131.3%</td><td style="text-align:center;">608.7%</td><td style="text-align:center;">402.9%</td></tr><tr><td style="text-align:center;">1957-65</td><td style="text-align:center;">164.1%</td><td style="text-align:center;">943.2%</td><td style="text-align:center;">588.5%</td></tr><tr><td style="text-align:center;">1957-66</td><td style="text-align:center;">122.9%</td><td style="text-align:center;">1,156.0%</td><td style="text-align:center;">704.2%</td></tr><tr><td style="text-align:center;">1957-67</td><td style="text-align:center;">165.3%</td><td style="text-align:center;">1,606.9%</td><td style="text-align:center;">932.6%</td></tr><tr><td style="text-align:center;">1957-68</td><td style="text-align:center;">185.7%</td><td style="text-align:center;">2,610.6%</td><td style="text-align:center;">1,403.5%</td></tr><tr><td style="text-align:center;"><strong>年化复合收益率</strong></td><td style="text-align:center;"><strong>9.1%</strong></td><td style="text-align:center;"><strong>31.6%</strong></td><td style="text-align:center;"><strong>25.3%</strong></td></tr></tbody></table><hr><h2 id="投资公司" tabindex="-1">投资公司 <a class="header-anchor" href="#投资公司" aria-label="Permalink to &quot;投资公司&quot;">​</a></h2><p>下页照例是两类最大共同基金（1957至1966年规模分列第一和第二位，目前仍为第二、第三名）、两只最大多元化封闭式投资公司的业绩对比表，这些公司通常保持95%-100%的普通股仓位。</p><table tabindex="0"><thead><tr><th style="text-align:center;">年份</th><th style="text-align:center;">Mass. Inv. Trust（1）</th><th style="text-align:center;">Investors Stock（1）</th><th style="text-align:center;">Lehman（2）</th><th style="text-align:center;">Tri-Cont（2）</th><th style="text-align:center;">道指</th><th style="text-align:center;">有限合伙人</th></tr></thead><tbody><tr><td style="text-align:center;">1957</td><td style="text-align:center;">-11.4%</td><td style="text-align:center;">-12.4%</td><td style="text-align:center;">-11.4%</td><td style="text-align:center;">-2.4%</td><td style="text-align:center;">-8.4%</td><td style="text-align:center;">9.3%</td></tr><tr><td style="text-align:center;">1958</td><td style="text-align:center;">42.7%</td><td style="text-align:center;">47.5%</td><td style="text-align:center;">40.8%</td><td style="text-align:center;">33.2%</td><td style="text-align:center;">38.5%</td><td style="text-align:center;">32.2%</td></tr><tr><td style="text-align:center;">1959</td><td style="text-align:center;">9.0%</td><td style="text-align:center;">10.3%</td><td style="text-align:center;">8.1%</td><td style="text-align:center;">8.4%</td><td style="text-align:center;">20.0%</td><td style="text-align:center;">20.9%</td></tr><tr><td style="text-align:center;">1960</td><td style="text-align:center;">-1.0%</td><td style="text-align:center;">-0.6%</td><td style="text-align:center;">2.5%</td><td style="text-align:center;">2.8%</td><td style="text-align:center;">-6.2%</td><td style="text-align:center;">18.6%</td></tr><tr><td style="text-align:center;">1961</td><td style="text-align:center;">25.6%</td><td style="text-align:center;">24.9%</td><td style="text-align:center;">23.6%</td><td style="text-align:center;">22.5%</td><td style="text-align:center;">22.4%</td><td style="text-align:center;">35.9%</td></tr><tr><td style="text-align:center;">1962</td><td style="text-align:center;">-9.8%</td><td style="text-align:center;">-13.4%</td><td style="text-align:center;">-14.4%</td><td style="text-align:center;">-10.0%</td><td style="text-align:center;">-7.6%</td><td style="text-align:center;">11.9%</td></tr><tr><td style="text-align:center;">1963</td><td style="text-align:center;">20.0%</td><td style="text-align:center;">16.5%</td><td style="text-align:center;">23.7%</td><td style="text-align:center;">18.3%</td><td style="text-align:center;">20.6%</td><td style="text-align:center;">30.5%</td></tr><tr><td style="text-align:center;">1964</td><td style="text-align:center;">15.9%</td><td style="text-align:center;">14.3%</td><td style="text-align:center;">13.6%</td><td style="text-align:center;">12.6%</td><td style="text-align:center;">18.7%</td><td style="text-align:center;">22.3%</td></tr><tr><td style="text-align:center;">1965</td><td style="text-align:center;">10.2%</td><td style="text-align:center;">9.8%</td><td style="text-align:center;">19.0%</td><td style="text-align:center;">10.7%</td><td style="text-align:center;">14.2%</td><td style="text-align:center;">36.9%</td></tr><tr><td style="text-align:center;">1966</td><td style="text-align:center;">-7.7%</td><td style="text-align:center;">-10.0%</td><td style="text-align:center;">-2.6%</td><td style="text-align:center;">-6.9%</td><td style="text-align:center;">-15.6%</td><td style="text-align:center;">16.8%</td></tr><tr><td style="text-align:center;">1967</td><td style="text-align:center;">20.0%</td><td style="text-align:center;">22.8%</td><td style="text-align:center;">28.0%</td><td style="text-align:center;">25.4%</td><td style="text-align:center;">19.0%</td><td style="text-align:center;">28.4%</td></tr><tr><td style="text-align:center;">1968</td><td style="text-align:center;">10.3%</td><td style="text-align:center;">8.1%</td><td style="text-align:center;">6.7%</td><td style="text-align:center;">6.8%</td><td style="text-align:center;">7.7%</td><td style="text-align:center;">45.6%</td></tr><tr><td style="text-align:center;"><strong>累计收益</strong></td><td style="text-align:center;">189.3%</td><td style="text-align:center;">167.7%</td><td style="text-align:center;">225.6%</td><td style="text-align:center;">200.2%</td><td style="text-align:center;">185.7%</td><td style="text-align:center;">1,403.5%</td></tr><tr><td style="text-align:center;"><strong>年化复合</strong></td><td style="text-align:center;">9.3%</td><td style="text-align:center;">8.6%</td><td style="text-align:center;">10.3%</td><td style="text-align:center;">9.6%</td><td style="text-align:center;">9.1%</td><td style="text-align:center;">25.3%</td></tr></tbody></table><blockquote><p>（1）以资产价值变化加当年持有人分红计算。 （2）1957-1967年数据来自1968年《穆迪银行与金融手册》，1968年为估算值。</p></blockquote><p>经过十二年，这四家基金（目前合计规模远超50亿美元，占投资公司行业10%以上）平均每年仅比道指高出不到一个百分点，这非常耐人寻味。</p><p>一些曾经的&quot;go-go&quot;基金如今已被改称为&quot;no-go&quot;基金。例如，杰拉尔德·蔡（Gerald Tsai）的曼哈顿基金——或许是全球最知名的激进投资公司——1968年收益为负6.9%。许多小型投资机构在1968年继续大幅跑赢大盘，但数量远不及1966和1967年。</p><p>投资管理行业——我曾在此部分对该行业过度的慵懒作风大加挞伐——如今在许多方面已转向极度亢奋。一位代表某机构（其古老而著名的名字你会认得）管理着超过10亿美元共同基金的基金经理，在1968年推出新的顾问服务时宣称：</p><blockquote><p>&quot;国内外经济的复杂性使资金管理成为一份全职工作。优秀的基金经理不能仅以周甚至以日为单位来研究证券，必须以分钟为单位来研究证券。&quot;</p></blockquote><p>哇！</p><p>这种东西让我出门喝百事可乐时都深感愧疚。当大量高度积极的人拿着大量资金在有限的合适证券上实践这套时，结果变得高度不可预测。有时候看着很有趣，有时候则令人震惊。</p><hr><h2 id="_1968年业绩分析" tabindex="-1">1968年业绩分析 <a class="header-anchor" href="#_1968年业绩分析" aria-label="Permalink to &quot;1968年业绩分析&quot;">​</a></h2><p>我们四类投资业务在1968年均表现出色。整体收益40,032,691美元，具体构成如下：</p><table tabindex="0"><thead><tr><th style="text-align:left;">类别</th><th style="text-align:right;">平均投资额</th><th style="text-align:right;">整体收益</th></tr></thead><tbody><tr><td style="text-align:left;">控制类</td><td style="text-align:right;">$24,996,998</td><td style="text-align:right;">$5,886,109</td></tr><tr><td style="text-align:left;">普通股——私人所有者</td><td style="text-align:right;">$16,363,100</td><td style="text-align:right;">$21,994,736</td></tr><tr><td style="text-align:left;">普通股——相对低估</td><td style="text-align:right;">$8,766,878</td><td style="text-align:right;">$4,271,825</td></tr><tr><td style="text-align:left;">套利类</td><td style="text-align:right;">$18,980,602</td><td style="text-align:right;">$7,317,128</td></tr><tr><td style="text-align:left;">杂项（主要是美国国库券）</td><td style="text-align:right;">$12,744,973</td><td style="text-align:right;">$839,496</td></tr><tr><td style="text-align:left;">总收入</td><td style="text-align:right;"></td><td style="text-align:right;">$40,309,294</td></tr><tr><td style="text-align:left;">减：一般费用（含利息）</td><td style="text-align:right;"></td><td style="text-align:right;">$276,603</td></tr><tr><td style="text-align:left;"><strong>整体收益</strong></td><td style="text-align:right;"></td><td style="text-align:right;"><strong>$40,032,691</strong></td></tr></tbody></table><p>几点说明（两年前的信中已提及，非博士候选人可直接跳至下一节）：</p><ol><li>上述各分类的说明见1965年1月18日信。如需回顾而您最爱的报刊亭没有口袋版，我们将乐意为您提供复印件。</li><li>分类并非一成不变。我们不做追溯修改，但初始分类决定有时具有主观性。有时后期分类证明是困难的——例如，一项套利交易最终未成，但由于与最初决定无关或仅部分相关的原因（例如固执），我选择继续持有。</li><li>以分类的平均投资额计算的回报率，相对于以初始投资额为基础的合伙公司回报率计算方法，会显著偏低。例如，我们以100买入的证券在12月31日平稳涨至200，按平均投资额150计算结果为66-2/3%，而传统方法计算为100%。换言之，上述数据使用月平均市值来计算平均投资额。</li><li>所有结果均基于100%自有资金、无杠杆的计算方式。利息和其他一般费用从总收益中扣除，不按分类分摊。与特定投资操作直接相关的费用，如卖空股票所支付的股息，按分类扣除。当证券被直接借入并卖空时，净多头（多头减空头）计入对应分类的平均投资额。</li><li>上述表格用途有限。各分类的结果主要由一两笔投资主导，不代表大量稳定数据（如美国男性死亡率或类似数据），无法据此得出结论或进行预测。相反，它们代表的是罕见的、非同质化的现象，所得出的关于各种行动方案的结论是非常试探性的——我们也是这样使用它们的。</li><li>最后，这些计算并没有像我们清点钱时那样细致入微，可能会出现笔误或计算错误，因为它们并非完全自检的。</li></ol><h3 id="控制类" tabindex="-1">控制类 <a class="header-anchor" href="#控制类" aria-label="Permalink to &quot;控制类&quot;">​</a></h3><p>总体而言，控股公司在1968年表现尚可。Diversified Retailing Company Inc.（持股80%）和Berkshire Hathaway Inc.（持股70%）的税后合并收益超过500万美元。</p><p>尤其出色的是由本·罗斯纳（Ben Rosner）运营的Associated Cotton Shops（DRC子公司）和由杰克·林格沃特（Jack Ringwalt）运营的National Indemnity Company（B-H子公司），两家公司均在所用资本上实现了约20%的回报率。在《财富》500强（美国最大制造企业，通用汽车领衔）中，1967年仅有37家公司达到这一水平，而我们的团队超越了IBM、通用电气、通用汽车、宝洁、杜邦、Control Data、惠普等略有名气（却未必更有价值）的公司。</p><p>我仍然会收到来自合伙人类似的评论：&quot;Berkshire涨了4个点——太棒了！&quot;或者&quot;我们怎么了？Berkshire上周跌了3个点？&quot;但市场价格对我们评估控股权益的估值完全无关。我们在1967年底以25的估值对应市场约20，在1968年底以31对应市场约37。无论市场是15和50，我们都会做同样的事。&quot;价格是你支付的，价值是你得到的。&quot;我们控股投资的成败与业务的运营表现相关——我们不会试图通过在证券市场上玩各种游戏来获利。</p><h3 id="普通股——私人所有者" tabindex="-1">普通股——私人所有者 <a class="header-anchor" href="#普通股——私人所有者" aria-label="Permalink to &quot;普通股——私人所有者&quot;">​</a></h3><p>多年来，这是我们按平均回报衡量的最佳类别，也是盈利交易占比最高的类别。这种方法是我学到的做生意的方式，以前它曾占据我们投资想法的很大一部分。在巴菲特合伙公司十二年历史上，我们在该类别的总利润可能是总亏损的五十倍以上。1968年，在一个简单行业理念上（以多种方式实施），收银机响得震天价响。我们甚至为此项工作收到了一笔可观的费用（已计入审计报告中的其他收入）。</p><p>目前该类别的总投资不足200万美元，而我没有任何东西可以补充。1968年像约翰斯敦洪水一样涌入的东西，在1969年看起来更像是阿尔图纳的漏水龙头。</p><h3 id="普通股——相对低估" tabindex="-1">普通股——相对低估 <a class="header-anchor" href="#普通股——相对低估" aria-label="Permalink to &quot;普通股——相对低估&quot;">​</a></h3><p>该类别贡献了1966年和1967年合并整体收益的三分之二。我去年提到，两年来的出色表现主要来自一个想法。我还说过：&quot;该组合中没有任何东西能接近以前的规模和潜力。&quot;我非常高兴地宣布，这一声明是完全正确的。我相当高兴地宣布，这一声明今年必须重述。</p><h3 id="套利类" tabindex="-1">套利类 <a class="header-anchor" href="#套利类" aria-label="Permalink to &quot;套利类&quot;">​</a></h3><p>该类别在1967年是一场灾难，在1968年表现出色。我们在该领域的相对集中度（每年集中于少数几笔交易，而大型套利机构每年可能涉及五十笔以上）使得年度结果比全面铺开的方式变化更大。我相信平均盈利能力与我们的策略相同，1968年使我对这一结论的感觉比1967年更好。</p><p>应当再次说明，与使用初始基础数据和杠杆的更常见方法相比，我们在该领域（以及其他类别）的业绩略有低估——尽管在套利业务中经常合理地使用杠杆。</p><hr><hr><p>我必须强调，理念的质量和数量目前处于历史最低点——这是我在1967年10月9日信中所述因素的结果，且此后这些因素已大幅加剧。</p><p>有时候我觉得我们办公室应该挂一块像达拉斯德州仪器公司总部的牌匾，上面写着：&quot;我们不相信奇迹，我们依靠它们。&quot;一个腿力和击球眼都已衰退的老运动员，偶尔还能挥出一支代打全垒打，但你不会因此改变阵容。</p><p>我们未来有许多重要的负面因素在发挥作用——虽然它们加总不等于徒劳，但肯定加总不出超过平庸的平均盈利能力。</p><hr><h2 id="纪念品" tabindex="-1">纪念品 <a class="header-anchor" href="#纪念品" aria-label="Permalink to &quot;纪念品&quot;">​</a></h2><p>正如我一位老友所说：&quot;怀旧已不再是以前的样子了。&quot;但不管怎样，让我们试一下。</p><p>巴菲特联合有限公司（Buffett Associates, Ltd.）是最初的合伙企业前身，成立于1956年5月5日，拥有七位有限合伙人（四位家人、三位密友），出资105,000美元，普通合伙人以身作则投入100,000美元。1956年期间还成立了另外两个单一家族有限合伙企业，到1957年1月1日合并净资产为303,726美元。1957年我们实现收益31,615.97美元，对应了首页所示的10.4%数字。1968年，我估计纽约证券交易所……</p><blockquote><p><em>（原文第127页末尾截断，原文出处：英文版1968年致合伙人信，1969年1月）</em></p></blockquote>',49)])])}const h=e(r,[["render",a]]);export{o as __pageData,h as default};
